VALUES
  ('social-worker-moex-05590', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '老人福利法、長期照顧服務法中有關費用、收費與基金之敘述，下列何者錯誤？', '["老人福利法規定，老人因直系血親卑親屬或依契約對其有扶養義務之人有疏忽、虐待、遺棄等，致有 生命、身體、健康或自由之危難，主管機關得依老人申請或職權予以適當短期保護及安置。老人保護 及安置所需之費用，由主管機關支付", "長期照顧服務法規定，中央主管機關應輔導地方主管機關參考地區所得、物價指數、服務品質等，提 供長照機構收費參考資訊；長照機構之收費項目及其金額，應報提供服務所在地之主管機關核定", "長期照顧服務法規定，長照機構收取費用，應開給載明收費項目及金額之收據，長照機構不得違反前 條收費規定，超額或擅立項目收費", "長期照顧服務法規定，中央主管機關為促進長照相關資源之發展、提升服務品質與效率、充實與均衡 服務及人力資源，應設置特種基金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05591', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '民國105年11月行政院核定實施「兒童與少年未來教育及發展帳戶」，符合資格之兒童及少年或其法定 代理人，於帳戶所有人年滿18歲前，每人每年最高儲蓄1萬5,000元；政府相對提撥同額款項，以鼓勵 適用對象之家庭踴躍配合。下列有關此方案的實施內容，何者錯誤？', '["帳戶存款得免列入「家庭財產」計算，以避免影響其低（中低）收入戶資格", "帳戶存款由承辦機構以定期存款計息，但帳戶所得孳息不得列入免納綜合所得稅", "已開戶之適用對象於其喪失低（中低）收入戶、長期安置資格，且經一年觀察期緩衝，確認離開低（中 低）收入戶扶助體系者，政府即停止相對提撥款，可維持帳戶持續存款，惟仍須於年滿18歲時，始可 提領存款", "兒少教育發展帳戶存金供為兒童及少年於年滿18歲後（高中或高職畢業），作為其接受高等教育、職 業訓練或就業、創業之用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05592', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依長期照顧服務法規定，長照人員、長照機構、財務及相關資源之發展、管理、轉介機制等構成之網絡， 稱為：', '["長照管理中心", "長照服務機構", "長照服務網絡", "長照服務體系"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05593', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會工作師法對於社會工作師之規範，下列敘述何者錯誤？', '["中央或直轄市、縣（市）主管機關依本法核發社會工作師證書或執照時，得收取證書費或執照費", "社會工作師執行業務時，應撰製社會工作紀錄，其紀錄應由執業之機關（構）、團體、事務所保存； 該紀錄保存年限不得少於7年", "一旦取得社會工作師證書即可執業，不需向所在地直轄市或縣（市）主管機關送驗社會工作師證書申 請登記", "社會工作師事務所之收費標準，由主管機關核定之，不得違反收費標準，超收費用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05594', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '兒童及少年福利與權益保障法、老人福利法、身心障礙者權益保障法，均在法中規定，須定期針對各服 務對象之生活狀況與需求調查進行研究並公布結果，下列敘述何者錯誤？', '["主管機關應每五年對兒童及少年身心發展、社會參與、生活及需求現況進行調查、統計及分析，並公 布結果", "主管機關應至少每五年舉辦老人生活狀況調查，出版統計報告", "各級政府應至少每五年舉辦身心障礙者之生活狀況、保健醫療、特殊教育、就業與訓練、交通及福利 等需求評估及服務調查研究，並應出版、公布調查研究結果", "行政院每十年辦理全國人口普查時，應將身心障礙者人口調查納入普查項目"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05595', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '身心障礙者權益保障法中有關於身心障礙者支持服務與經濟安全的敘述，下列何者正確？', '["未提供對號座之大眾運輸工具，應設置供身心障礙者優先乘坐之博愛座，其比率不低於總座位數百分 之五", "大眾運輸工具應規劃設置便於各類身心障礙者行動與使用之無障礙設施及設備", "公共停車場應保留百分之五停車位，作為行動不便之身心障礙者專用停車位", "車位未滿五十個之公共停車場，至少應保留三個身心障礙者專用停車位"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05596', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年福利與權益保障法規定，主管機關應邀集兒童及少年福利相關學者或專家、民間相關機 構、團體代表及目的事業主管機關代表，協調、研究、審議、諮詢及推動兒童及少年福利政策。該小組 成員的設置，下列何者正確？', '["兒童及少年福利相關學者、專家及民間相關機構、團體代表不得少於三分之一", "應以該主管機關首長為召集人", "單一性別不得少於二分之一", "應邀請兒童及少年代表"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05597', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據國民年金法，國民年金保險之保險事故，不包含下列那一項？', '["老年", "長期照顧", "死亡", "生育"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05598', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '近 3 年來因衛生福利部無法支付國民年金屬政府應負擔的保費及差額金，向國保基金借款因應，利息已 高達兩億多元。根據國民年金法規定，中央主管機關應補助之保險費及應負擔之款項，有幾個籌措支應 來源，下列何者不是法定來源？', '["公益彩券盈餘", "調增營業稅徵收率百分之一", "政府預算撥補", "基金孳息收入"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05599', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '性別工作平等法第23條規定，僱用幾人以上受僱者之雇主，應提供哺（集）乳室、托兒設施或適當之托 兒措施？', '["100人", "50人", "200人", "300人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
